package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsNull_ThenReturnFalse() {
        assertFalse(csvFormat.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsSet_ThenReturnTrue() throws NoSuchFieldException, IllegalAccessException {
        // Given
        CSVFormat csvFormatWithCommentMarker = CSVFormat.DEFAULT.withCommentMarker('#');

        // When
        boolean result = csvFormatWithCommentMarker.isCommentMarkerSet();

        // Then
        assertTrue(result);
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsSetToNull_ThenReturnFalse() throws NoSuchFieldException, IllegalAccessException {
        // Given
        CSVFormat csvFormatWithNullCommentMarker = CSVFormat.DEFAULT.withCommentMarker(null);

        // When
        boolean result = csvFormatWithNullCommentMarker.isCommentMarkerSet();

        // Then
        assertFalse(result);
    }

    @Test
    public void testIsCommentMarkerSet_WhenCommentMarkerIsSetToNullUsingReflection_ThenReturnFalse() throws NoSuchFieldException, IllegalAccessException {
        // Given
        CSVFormat csvFormatWithNullCommentMarker = CSVFormat.DEFAULT.withCommentMarker(null);

        // When
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(csvFormatWithNullCommentMarker, null);
        boolean result = csvFormatWithNullCommentMarker.isCommentMarkerSet();

        // Then
        assertFalse(result);
    }
}
